SELECT 
FROM comment c
LEFT JOIN user u ON c.user_id = u.id
WHERE c.blog_id = #{blogId}
 AND c.status = #{status} 
ORDER BY c.create_time ASC

SELECT 
FROM comment c
LEFT JOIN user u ON c.user_id = u.id
WHERE (c.blog_id IS NULL OR c.blog_id = 0)
 AND c.status = #{status} 
ORDER BY c.create_time DESC LIMIT #{offset}, #{limit}

SELECT 
FROM comment c
LEFT JOIN user u ON c.user_id = u.id

     AND c.blog_id = #{blogId} 
     AND c.status = #{status} 

ORDER BY c.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM comment

     AND blog_id = #{blogId} 
     AND status = #{status}
